const body = $json.body || $json;
const source = body.payload || body;
const statusMap = { pago:'paid', paga:'paid', paid:'paid', aprovado:'paid', approved:'paid', pendente:'open', pending:'open', aberta:'open', open:'open', vencida:'overdue', overdue:'overdue', cancelada:'cancelled', cancelled:'cancelled', canceled:'cancelled', expirada:'cancelled', expired:'cancelled' };
const rawStatus = String(source.status || source.situacao || source.event || 'open').toLowerCase().trim();
return [{json:{
  token: source.token || 'CONFIGURE_O_TOKEN_DO_GATEWAY',
  invoice_number: source.invoice_number || source.reference_id || source.referencia || '',
  external_id: source.external_id || source.charge_id || source.id || '',
  status: statusMap[rawStatus] || rawStatus,
  checkout_url: source.checkout_url || source.payment_url || source.link || ''
}}];
